#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=2e3+5;
double dis[MAXN][MAXN],x[MAXN],y[MAXN],a[MAXN],m[MAXN],a1,a2=llinf,n;
char g[MAXN][MAXN];
signed main(void)
{

    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	ios::sync_with_stdio(0);
	cin.tie(0);
	cin>>n;
	FOR(i,1,n)//init
    {
        FOR(j,1,n)
        {
            if(i!=j)dis[i][j]=llinf;
            else dis[i][j]=0;
        }
    }
    FOR(i,1,n)
    {
		cin>>x[i]>>y[i];
	}
    FOR(i,1,n)//solve
    {
        FOR(j,1,n)
        {
            cin>>g[i][j];
            if(g[i][j]=='1')dis[i][j]=sqrt((x[i]-x[j])*(x[i]-x[j])+(y[i]-y[j])*(y[i]-y[j]));
        }
    }
    FOR(k,1,n)//floyd
    {
        FOR(i,1,n)
        {
            FOR(j,1,n)
			{
				dis[i][j]=min(dis[i][j],dis[i][k]+dis[k][j]);
			}
        }
    }
	FOR(i,1,n)
	{
        FOR(j,1,n)
        {
            if(dis[i][j]<llinf/2)a[i]=max(a[i],dis[i][j]);
        }
        a1=max(a1,a[i]);
    }
    FOR(i,1,n)
    {
        FOR(j,1,n)
        {
            if(dis[i][j]<llinf/2)m[i]=max(m[i],a[j]);
        }
    }
    FOR(i,1,n)
    {
        FOR(j,1,n)
        {
			if(dis[i][j]>inf/2)a2=min(a2,max(a[i]+a[j]+sqrt((x[i]-x[j])*(x[i]-x[j])+(y[i]-y[j])*(y[i]-y[j])),max(m[i],m[j])));
        }
    }
    printf("%.6lf",a2);
    return false;
}
